import{_ as t,a,b as d}from"./chunks/配置容量限制.DkdWbdOw.js";import{_ as i,o,c as n,a2 as l}from"./chunks/framework.DnrXFDHb.js";const g=JSON.parse('{"title":"Add a Cloudflare R2 Channel","description":"","frontmatter":{},"headers":[],"relativePath":"en/upload/cloudflare-r2.md","filePath":"en/upload/cloudflare-r2.md","lastUpdated":1781962217000}'),r={name:"en/upload/cloudflare-r2.md"};function h(c,e,s,u,b,p){return o(),n("div",null,[...e[0]||(e[0]=[l('<h1 id="add-a-cloudflare-r2-channel" tabindex="-1">Add a Cloudflare R2 Channel <a class="header-anchor" href="#add-a-cloudflare-r2-channel" aria-label="Permalink to &quot;Add a Cloudflare R2 Channel&quot;">​</a></h1><h2 id="best-fit" tabindex="-1">Best Fit <a class="header-anchor" href="#best-fit" aria-label="Permalink to &quot;Best Fit&quot;">​</a></h2><p>Use Cloudflare R2 when:</p><ul><li>Your ImgBed site is already deployed on Cloudflare and you want to store files in an R2 bucket under the same Cloudflare account.</li><li>You do not want to configure a separate S3 endpoint, access key, and secret key.</li><li>You want reads and writes to go through the Worker or Pages R2 binding with minimal setup.</li></ul><p>In short:</p><p>The R2 channel is not created manually inside the ImgBed admin panel. You first bind an R2 bucket to the Cloudflare project, and the binding variable name must be <code>img_r2</code>.</p><h2 id="what-you-need-before-you-start" tabindex="-1">What You Need Before You Start <a class="header-anchor" href="#what-you-need-before-you-start" aria-label="Permalink to &quot;What You Need Before You Start&quot;">​</a></h2><ul><li>A Cloudflare account.</li><li>An existing R2 bucket.</li><li>Permission to manage the Cloudflare project where ImgBed is deployed.</li></ul><h2 id="configure-it-in-cloudflare" tabindex="-1">Configure It in Cloudflare <a class="header-anchor" href="#configure-it-in-cloudflare" aria-label="Permalink to &quot;Configure It in Cloudflare&quot;">​</a></h2><h3 id="_1-create-an-r2-bucket" tabindex="-1">1. Create an R2 Bucket <a class="header-anchor" href="#_1-create-an-r2-bucket" aria-label="Permalink to &quot;1. Create an R2 Bucket&quot;">​</a></h3><ol><li>Log in to the Cloudflare Dashboard.</li><li>Open <code>R2 Object Storage</code>.</li><li>Click Create bucket.</li><li>Choose a bucket name, for example <code>imgbed</code>.</li></ol><p>This bucket is where uploaded files will be stored.</p><p><img src="'+t+'" alt="Create an R2 bucket" loading="lazy"></p><h3 id="_2-bind-the-bucket-to-the-imgbed-project" tabindex="-1">2. Bind the Bucket to the ImgBed Project <a class="header-anchor" href="#_2-bind-the-bucket-to-the-imgbed-project" aria-label="Permalink to &quot;2. Bind the Bucket to the ImgBed Project&quot;">​</a></h3><p>Choose the binding location based on your deployment type:</p><table tabindex="0"><thead><tr><th>Deployment Type</th><th>Binding Location</th></tr></thead><tbody><tr><td>Pages</td><td>Current Pages project -&gt; Settings -&gt; Functions -&gt; R2 bucket bindings</td></tr><tr><td>Worker</td><td>Current Worker -&gt; Settings -&gt; Bindings -&gt; R2 bucket bindings</td></tr></tbody></table><p>When adding the binding, the important fields are:</p><table tabindex="0"><thead><tr><th>Field</th><th>Value</th></tr></thead><tbody><tr><td>Variable name</td><td><code>img_r2</code></td></tr><tr><td>R2 bucket</td><td>Select the bucket you created.</td></tr></tbody></table><p>The variable name must be exactly <code>img_r2</code>. Uploading, reading, and deleting R2 files all depend on this binding name.</p><h3 id="_3-redeploy-the-project" tabindex="-1">3. Redeploy the Project <a class="header-anchor" href="#_3-redeploy-the-project" aria-label="Permalink to &quot;3. Redeploy the Project&quot;">​</a></h3><p>After saving the binding, redeploy ImgBed so the Worker or Pages runtime can access <code>img_r2</code>.</p><h2 id="what-you-will-see-in-imgbed" tabindex="-1">What You Will See in ImgBed <a class="header-anchor" href="#what-you-will-see-in-imgbed" aria-label="Permalink to &quot;What You Will See in ImgBed&quot;">​</a></h2><p>After the R2 binding is available, open:</p><ol><li>System Settings.</li><li>Upload Settings.</li><li>The <code>Cloudflare R2</code> channel.</li></ol><p>The system automatically creates one fixed channel:</p><table tabindex="0"><thead><tr><th>Field</th><th>Fixed Value</th></tr></thead><tbody><tr><td>Channel name</td><td><code>Cloudflare R2</code></td></tr><tr><td>Channel type</td><td><code>cfr2</code></td></tr><tr><td>Storage mode</td><td><code>binding</code></td></tr><tr><td>Configuration source</td><td>Environment binding</td></tr></tbody></table><p>This is a fixed binding channel. You do not need to click Add Channel to create it, and it cannot be deleted like a regular channel.</p><h2 id="editable-fields-in-the-admin-panel" tabindex="-1">Editable Fields in the Admin Panel <a class="header-anchor" href="#editable-fields-in-the-admin-panel" aria-label="Permalink to &quot;Editable Fields in the Admin Panel&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Field</th><th>What It Does</th><th>Required</th></tr></thead><tbody><tr><td>Enable channel</td><td>Controls whether R2 participates in upload selection.</td><td>Yes</td></tr><tr><td>Account ID</td><td>Used only when quota limits are enabled and official R2 usage needs to be queried.</td><td>Recommended when quota limits are enabled</td></tr><tr><td>Bucket name</td><td>Used only when quota limits are enabled and official R2 usage needs to be queried.</td><td>Recommended when quota limits are enabled</td></tr><tr><td>Quota limit</td><td>Controls whether this R2 channel participates in upload selection based on capacity.</td><td>No</td></tr><tr><td>Threshold</td><td>Stops writing to this channel after usage reaches the specified percentage.</td><td>Required when quota limits are enabled</td></tr></tbody></table><p>You can copy the Account ID from the account information panel in the Cloudflare dashboard. Fill it in only if you want ImgBed to query and enforce R2 quota usage.</p><p><img src="'+a+'" alt="Get the Account ID" loading="lazy"></p><h2 id="setup-steps" tabindex="-1">Setup Steps <a class="header-anchor" href="#setup-steps" aria-label="Permalink to &quot;Setup Steps&quot;">​</a></h2><ol><li>Create an R2 bucket in Cloudflare.</li><li>Open the Cloudflare settings for the ImgBed project.</li><li>Add an R2 bucket binding.</li><li>Set <code>Variable name</code> to <code>img_r2</code>.</li><li>Select the R2 bucket you created.</li><li>Save the binding and redeploy ImgBed.</li><li>Return to ImgBed -&gt; System Settings -&gt; Upload Settings.</li><li>Confirm that the <code>Cloudflare R2</code> channel appears and is enabled.</li></ol><p>If you want R2 to participate in upload selection based on capacity, enable the quota limit, then enter the Account ID, bucket name, quota limit, and threshold before saving.</p><p><img src="'+d+'" alt="Configure quota limits" loading="lazy"></p><h2 id="how-to-verify-it" tabindex="-1">How to Verify It <a class="header-anchor" href="#how-to-verify-it" aria-label="Permalink to &quot;How to Verify It&quot;">​</a></h2><ul><li>The fixed <code>Cloudflare R2</code> channel appears in Upload Settings.</li><li>The channel card shows that it is enabled.</li><li>A small test file uploads successfully, and the returned link opens normally.</li><li>If opening a file returns <code>R2 database binding is not configured</code>, the runtime did not receive the <code>img_r2</code> binding. Check the binding name in Cloudflare and redeploy the project.</li></ul>',37)])])}const y=i(r,[["render",h]]);export{g as __pageData,y as default};
